"""
Config merger. Merges multiple config dicts with precedence rules.
"""
from dataclasses import dataclass, field


class MergeConflict(ValueError):
    """Raised by deep_merge when strategy='strict' and types conflict."""


class FlattenConflict(TypeError):
    """Raised by unflatten_config when a key is both a scalar and a section prefix."""


@dataclass
class MergeReport:
    """Describes what a merge would do without modifying anything."""
    keys_added: list = field(default_factory=list)
    keys_overridden: list = field(default_factory=list)
    keys_removed: list = field(default_factory=list)
    type_conflicts: list = field(default_factory=list)


def deep_merge(base, override, path="", strategy="override"):
    """Merge override into base, returning a new dict.

    Rules:
    - Scalars: override wins
    - Dicts: recursive merge
    - Lists: concatenate (base + override)
    - None in override: removes the key from base

    Args:
        strategy: conflict resolution for type mismatches (list vs scalar, dict vs scalar):
            "override" (default): override always wins
            "strict": raise MergeConflict on type mismatches
            "append": append scalar to list when base is list, override is scalar
            "protect": base wins on type-conflicting keys
    """
    result = dict(base)

    for key, value in override.items():
        if value is None:
            # None means "remove this key"
            result.pop(key, None)
            continue

        if key in result:
            base_val = result[key]

            if isinstance(base_val, dict) and isinstance(value, dict):
                # Both are dicts: recursive merge
                result[key] = deep_merge(base_val, value, f"{path}.{key}", strategy)
            elif isinstance(base_val, list) and isinstance(value, list):
                # Both are lists: concatenate
                result[key] = base_val + value
            elif isinstance(base_val, list) and not isinstance(value, list):
                # Type conflict: base is list, override is scalar
                key_path = f"{path}.{key}" if path else key
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type mismatch at '{key_path}': base is list, override is {type(value).__name__}"
                    )
                elif strategy == "append":
                    result[key] = base_val + [value]
                elif strategy == "protect":
                    pass  # base wins, leave result[key] unchanged
                else:  # "override"
                    result[key] = value
            elif isinstance(base_val, dict) and not isinstance(value, dict):
                # Type conflict: base is dict, override is scalar
                key_path = f"{path}.{key}" if path else key
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type mismatch at '{key_path}': base is dict, override is {type(value).__name__}"
                    )
                elif strategy == "protect":
                    pass  # base wins
                else:  # "override" or "append"
                    result[key] = value
            else:
                # Scalar vs scalar (or scalar vs list when base is scalar)
                if strategy == "protect":
                    pass  # base wins on all conflicts
                else:
                    result[key] = value
        else:
            result[key] = value

    return result


def merge_configs(*configs):
    """Merge multiple configs with left-to-right precedence.

    First config is lowest priority, last is highest.

    Example:
        merge_configs(defaults, user_config, cli_overrides)
    """
    if not configs:
        return {}

    result = configs[0]
    for config in configs[1:]:
        result = deep_merge(result, config)

    return result


def merge_report(base, override):
    """Describe what deep_merge(base, override) would do without modifying anything.

    Returns a MergeReport with:
        keys_added: keys in override not present in base
        keys_overridden: keys present in both whose values differ
        keys_removed: keys set to None in override (would be removed)
        type_conflicts: keys present in both where types are incompatible
    """
    keys_added = []
    keys_overridden = []
    keys_removed = []
    type_conflicts = []

    for key, value in override.items():
        if value is None:
            if key in base:
                keys_removed.append(key)
        elif key not in base:
            keys_added.append(key)
        else:
            base_val = base[key]

            # Detect type conflicts
            if (
                (isinstance(base_val, list) and not isinstance(value, list))
                or (isinstance(base_val, dict) and not isinstance(value, dict))
                or (not isinstance(base_val, (list, dict)) and isinstance(value, (list, dict)))
            ):
                type_conflicts.append(key)

            # Detect value changes
            if base_val != value:
                keys_overridden.append(key)

    return MergeReport(
        keys_added=keys_added,
        keys_overridden=keys_overridden,
        keys_removed=keys_removed,
        type_conflicts=type_conflicts,
    )


def flatten_config(config, prefix="", sep="."):
    """Flatten a nested config dict into dot-separated keys.

    Example:
        {"a": {"b": 1, "c": 2}} -> {"a.b": 1, "a.c": 2}
    """
    result = {}
    for key, value in config.items():
        full_key = f"{prefix}{sep}{key}" if prefix else key
        if isinstance(value, dict):
            result.update(flatten_config(value, full_key, sep))
        else:
            result[full_key] = value
    return result


def unflatten_config(flat_config, sep="."):
    """Unflatten dot-separated keys back into nested dict.

    Example:
        {"a.b": 1, "a.c": 2} -> {"a": {"b": 1, "c": 2}}

    Raises FlattenConflict if a key is both a scalar value and a section prefix.
    """
    result = {}
    for key, value in flat_config.items():
        parts = key.split(sep)
        target = result
        for part in parts[:-1]:
            if part not in target:
                target[part] = {}
            elif not isinstance(target[part], dict):
                raise FlattenConflict(
                    f"Key conflict: '{part}' is both a scalar value and a section prefix in key '{key}'"
                )
            target = target[part]
        target[parts[-1]] = value
    return result

"""Tests for merge strategies, merge_report, and unflatten_config conflict handling."""
import pytest
from src.merger import (
    deep_merge,
    merge_report,
    MergeConflict,
    FlattenConflict,
    MergeReport,
    unflatten_config,
)


# ---------------------------------------------------------------------------
# Strategy: override (default)
# ---------------------------------------------------------------------------

class TestStrategyOverride:
    def test_list_scalar_replaces_list(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="override")
        assert result == {"tags": "c"}

    def test_dict_scalar_replaces_dict(self):
        result = deep_merge({"db": {"host": "localhost"}}, {"db": "none"}, strategy="override")
        assert result == {"db": "none"}

    def test_scalar_scalar_override_wins(self):
        assert deep_merge({"x": 1}, {"x": 99}, strategy="override") == {"x": 99}

    def test_new_keys_added(self):
        result = deep_merge({"a": 1}, {"b": 2}, strategy="override")
        assert result == {"a": 1, "b": 2}

    def test_is_default_strategy(self):
        # No strategy arg — should behave same as strategy="override"
        result = deep_merge({"tags": ["a"]}, {"tags": "x"})
        assert result == {"tags": "x"}


# ---------------------------------------------------------------------------
# Strategy: strict
# ---------------------------------------------------------------------------

class TestStrategyStrict:
    def test_list_scalar_raises(self):
        with pytest.raises(MergeConflict, match="list"):
            deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="strict")

    def test_dict_scalar_raises(self):
        with pytest.raises(MergeConflict, match="dict"):
            deep_merge({"db": {"host": "localhost"}}, {"db": "none"}, strategy="strict")

    def test_scalar_scalar_ok(self):
        result = deep_merge({"x": 1}, {"x": 2}, strategy="strict")
        assert result == {"x": 2}

    def test_list_list_ok(self):
        result = deep_merge({"tags": ["a"]}, {"tags": ["b"]}, strategy="strict")
        assert result == {"tags": ["a", "b"]}

    def test_dict_dict_ok(self):
        result = deep_merge({"db": {"port": 5432}}, {"db": {"port": 3306}}, strategy="strict")
        assert result == {"db": {"port": 3306}}

    def test_new_keys_not_a_conflict(self):
        result = deep_merge({"a": 1}, {"b": [1, 2]}, strategy="strict")
        assert result == {"a": 1, "b": [1, 2]}

    def test_error_includes_key_path(self):
        with pytest.raises(MergeConflict, match="tags"):
            deep_merge({"tags": ["a"]}, {"tags": "c"}, strategy="strict")

    def test_nested_conflict_raises(self):
        base = {"server": {"ports": [80, 443]}}
        override = {"server": {"ports": "8080"}}
        with pytest.raises(MergeConflict):
            deep_merge(base, override, strategy="strict")


# ---------------------------------------------------------------------------
# Strategy: append
# ---------------------------------------------------------------------------

class TestStrategyAppend:
    def test_scalar_appended_to_list(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="append")
        assert result == {"tags": ["a", "b", "c"]}

    def test_int_appended_to_list(self):
        result = deep_merge({"nums": [1, 2]}, {"nums": 3}, strategy="append")
        assert result == {"nums": [1, 2, 3]}

    def test_list_list_still_concatenates(self):
        result = deep_merge({"tags": ["a"]}, {"tags": ["b", "c"]}, strategy="append")
        assert result == {"tags": ["a", "b", "c"]}

    def test_dict_scalar_uses_override(self):
        # append only special-cases list+scalar; dict+scalar falls through to override
        result = deep_merge({"db": {"host": "localhost"}}, {"db": "none"}, strategy="append")
        assert result == {"db": "none"}

    def test_scalar_scalar_override_wins(self):
        result = deep_merge({"x": 1}, {"x": 99}, strategy="append")
        assert result == {"x": 99}


# ---------------------------------------------------------------------------
# Strategy: protect
# ---------------------------------------------------------------------------

class TestStrategyProtect:
    def test_list_scalar_base_wins(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="protect")
        assert result == {"tags": ["a", "b"]}

    def test_dict_scalar_base_wins(self):
        result = deep_merge({"db": {"host": "localhost"}}, {"db": "none"}, strategy="protect")
        assert result == {"db": {"host": "localhost"}}

    def test_scalar_scalar_base_wins(self):
        result = deep_merge({"x": 1}, {"x": 99}, strategy="protect")
        assert result == {"x": 1}

    def test_new_keys_still_added(self):
        result = deep_merge({"a": 1}, {"b": 2}, strategy="protect")
        assert result == {"a": 1, "b": 2}

    def test_none_still_removes(self):
        result = deep_merge({"a": 1, "b": 2}, {"a": None}, strategy="protect")
        assert result == {"b": 2}

    def test_nested_dict_protect(self):
        base = {"server": {"ports": [80, 443]}}
        override = {"server": {"ports": "8080"}}
        result = deep_merge(base, override, strategy="protect")
        assert result == {"server": {"ports": [80, 443]}}


# ---------------------------------------------------------------------------
# merge_report
# ---------------------------------------------------------------------------

class TestMergeReport:
    def test_keys_added(self):
        report = merge_report({"a": 1}, {"b": 2, "c": 3})
        assert set(report.keys_added) == {"b", "c"}
        assert report.keys_overridden == []
        assert report.keys_removed == []
        assert report.type_conflicts == []

    def test_keys_overridden(self):
        report = merge_report({"a": 1, "b": 2}, {"a": 99})
        assert report.keys_overridden == ["a"]
        assert report.keys_added == []

    def test_keys_removed(self):
        report = merge_report({"a": 1, "b": 2}, {"a": None})
        assert report.keys_removed == ["a"]
        assert report.keys_added == []
        assert report.keys_overridden == []

    def test_none_for_missing_key_not_reported(self):
        # None for a key not in base — no removal actually happens
        report = merge_report({"a": 1}, {"z": None})
        assert report.keys_removed == []

    def test_type_conflicts_list_scalar(self):
        report = merge_report({"tags": ["a", "b"]}, {"tags": "c"})
        assert "tags" in report.type_conflicts
        assert "tags" in report.keys_overridden

    def test_type_conflicts_dict_scalar(self):
        report = merge_report({"db": {"host": "localhost"}}, {"db": "none"})
        assert "db" in report.type_conflicts

    def test_type_conflicts_scalar_list(self):
        report = merge_report({"x": 1}, {"x": [1, 2]})
        assert "x" in report.type_conflicts

    def test_no_modification(self):
        base = {"a": 1, "tags": ["x"]}
        override = {"a": 2, "tags": "y", "b": 3}
        merge_report(base, override)
        # base and override must be untouched
        assert base == {"a": 1, "tags": ["x"]}
        assert override == {"a": 2, "tags": "y", "b": 3}

    def test_returns_merge_report_instance(self):
        report = merge_report({}, {})
        assert isinstance(report, MergeReport)

    def test_same_value_not_in_overridden(self):
        report = merge_report({"a": 1}, {"a": 1})
        assert report.keys_overridden == []
        assert report.keys_added == []

    def test_mixed_report(self):
        base = {"host": "localhost", "port": 5432, "tags": ["db"], "debug": True}
        override = {"port": 3306, "tags": "primary", "name": "mydb", "debug": None}
        report = merge_report(base, override)
        assert "name" in report.keys_added
        assert "port" in report.keys_overridden
        assert "debug" in report.keys_removed
        assert "tags" in report.type_conflicts


# ---------------------------------------------------------------------------
# unflatten_config conflict handling
# ---------------------------------------------------------------------------

class TestUnflattenConflict:
    def test_raises_flatten_conflict(self):
        with pytest.raises(FlattenConflict):
            unflatten_config({"a": 1, "a.b": 2})

    def test_flatten_conflict_is_type_error(self):
        # FlattenConflict subclasses TypeError so existing catch clauses still work
        with pytest.raises(TypeError):
            unflatten_config({"a": 1, "a.b": 2})

    def test_error_message_is_descriptive(self):
        with pytest.raises(FlattenConflict, match="'a'"):
            unflatten_config({"a": 1, "a.b": 2})

    def test_deep_conflict(self):
        with pytest.raises(FlattenConflict):
            unflatten_config({"x.y": 1, "x.y.z": 2})

    def test_no_conflict_still_works(self):
        result = unflatten_config({"a.b": 1, "a.c": 2})
        assert result == {"a": {"b": 1, "c": 2}}
